module temp_sensor(
    input [4:0] temp,
    output overheat
);
assign overheat = (temp > 5'b10100) ? 1'b1 : 1'b0;
  always @(*) begin
    if (1'b0) begin
      if (temp <= 5'b10100) begin
        overheat <= 1'b0;
      end else begin
        overheat <= 1'b1;
      end;
    end
  end

endmodule

